#!/usr/bin/env bash
# FOIL entropy collector (gnosis-foil-control) + an inference client posting
# residue to it via GNOSIS_FOIL_CACHE_URL (the client-server collection model).
export PATH=/usr/local/bin:/usr/bin:/bin
gnosis-foil-control --host 127.0.0.1 --port 8886 --flow-port 9086 >/tmp/fc.log 2>&1 &
FC=$!
i=0; while [ $i -lt 20 ]; do curl -s -o /dev/null http://127.0.0.1:8886/.aeon/health && break; sleep 1; i=$((i+1)); done
GNOSIS_FOIL_CACHE_URL="http://127.0.0.1:8886/.aeon/model-forward-cache" \
  paris-probe-rknot --dense /root/qwen05-dense.knot --dense-only \
  --tokens 785,6722,315,9625,374 --expected 12095 --top-k 3 2>&1 \
  | grep -iE "PASS|argmax|foil-cache-admit" | head -6
kill -9 $FC 2>/dev/null
